<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function atError(m){$('.isi_warning_delete').text(m||'Attendance gagal diproses.');$('.error_data_delete').fadeIn();}
function atFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),employee_id:$('#filter_employee_id').val(),department_code:$('#filter_department_code').val(),attendance_type:$('#filter_attendance_type').val(),attendance_status:$('#filter_attendance_status').val(),attendance_source:$('#filter_attendance_source').val(),keyword:$('#filter_keyword').val()};}
function atSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function atAjax(selector,act,placeholder,parent){$(selector).select2({width:'100%',allowClear:true,placeholder:placeholder,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/attendance/attendance_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||'',attendance_date:$('#attendance_date').val()};},processResults:function(d){return{results:d.results||[]};}}});}
function atReset(title){$('#form_attendance')[0].reset();$('#at_id').val('');$('#shift_schedule_id,#employee_id,#department_code,#shift_id,#work_location_id').val(null).trigger('change');$('#attendance_date').val('<?=$today;?>');$('#attendance_type').val('REGULAR').trigger('change');$('#attendance_source').val('MANUAL').trigger('change');$('#attendance_status').val('DRAFT').trigger('change');$('#break_minutes').val(60);$('#planned_hours').val(8);$('#actual_hours').val(0);$('#modal_attendance .modal-title').text(title||'Create Attendance');}
$(function(){if($.fn.datepicker){$('.at-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_attendance_type,#filter_attendance_status,#filter_attendance_source,#attendance_type,#attendance_source,#attendance_status').select2({width:'100%',allowClear:true});atAjax('#filter_employee_id','employee_search','Semua Employee');atAjax('#filter_department_code','department_search','Semua Department');atAjax('#shift_schedule_id','shift_schedule_search','Pilih Shift Schedule',$('#modal_attendance'));atAjax('#employee_id','employee_search','Pilih Employee',$('#modal_attendance'));atAjax('#department_code','department_search','Pilih Department',$('#modal_attendance'));atAjax('#shift_id','shift_search','Pilih Shift',$('#modal_attendance'));atAjax('#work_location_id','work_location_search','Pilih Work Location',$('#modal_attendance'));atAjax('#sync_device_id','device_search','Pilih Mesin',$('#modal_at_sync_machine'));atAjax('#sync_employee_id','employee_search','Semua Pegawai',$('#modal_at_sync_machine'));}
var dt=$('#dtb_attendance').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'210px',targets:1}],ajax:{url:'<?=base_admin();?>modul/attendance/attendance_data.php',type:'post',data:function(d){$.extend(d,atFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_posted').text(k.posted||0);$('#kpi_late_count').text(k.late_count||0);$('#kpi_early_count').text(k.early_count||0);$('#kpi_absence_count').text(k.absence_count||0);$('#kpi_overtime_hours').text(k.overtime_hours||0);return j.data||[];},error:function(x){console.log(x.responseText);atError('Data Attendance gagal dimuat.');}}});
$('#btn_open_at').click(function(){atReset('Create Attendance');$('#modal_attendance').modal({backdrop:'static',keyboard:false});});$('#btn_sync_machine_at').click(function(){$('#form_at_sync_machine')[0].reset();$('#sync_tgl_awal,#sync_tgl_akhir').val('<?=$today;?>');$('#sync_device_id,#sync_employee_id').val(null).trigger('change');$('#at_sync_machine_result').hide().html('');$('#modal_at_sync_machine').modal({backdrop:'static',keyboard:false});});$('#btn_import_at').click(function(){$('#form_at_import')[0].reset();$('#at_import_result').hide().html('');$('#modal_at_import').modal({backdrop:'static',keyboard:false});});$('#btn_template_at').click(function(){window.location='<?=base_admin();?>modul/attendance/attendance_action.php?act=template_import';});$('#btn_filter_at').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_at').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_employee_id,#filter_department_code,#filter_attendance_type,#filter_attendance_status,#filter_attendance_source').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_at').click(function(){window.location='<?=base_admin();?>modul/attendance/attendance_action.php?act=export&'+$.param(atFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#attendance_no,#absence_reason').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#form_at_sync_machine').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> Sinkron...');$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=sync_machine_dummy',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-refresh"></i> Sinkron');if(r.status==='good'){var html='<div class="alert alert-success"><b>'+($('<div>').text(r.message||'Sinkron berhasil.').html())+'</b><br>Mesin: '+($('<div>').text(r.device||'-').html())+'<br>Range: '+($('<div>').text(r.date_range||'-').html())+'<br>Pegawai: '+($('<div>').text(r.employee||'-').html())+'<br>Simulasi log: '+(r.logs||0)+'<br>Batch: '+($('<div>').text(r.batch_no||'-').html())+'<br><small>'+($('<div>').text(r.note||'').html())+'</small></div>';$('#at_sync_machine_result').html(html).show();dt.draw(false);Swal.fire('Sukses','Dummy sync mesin berhasil.','success');}else{$('#at_sync_machine_result').html('<div class="alert alert-danger">'+($('<div>').text(r.error_message||'Sinkron gagal.').html())+'</div>').show();}},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-refresh"></i> Sinkron');$('#at_sync_machine_result').html('<div class="alert alert-danger">'+($('<div>').text(x.responseText||'Sinkron gagal.').html())+'</div>').show();});});
$('#form_at_import').submit(function(e){e.preventDefault();var fd=new FormData(this),b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> Importing...');$.ajax({url:'<?=base_admin();?>modul/attendance/attendance_action.php?act=import',type:'POST',data:fd,dataType:'json',processData:false,contentType:false,success:function(r){b.prop('disabled',false).html('<i class="fa fa-upload"></i> Upload & Import');if(r.status==='good'){var errs=r.errors||[],html='<div class="alert alert-success"><b>Import selesai.</b><br>Inserted: '+(r.inserted||0)+' | Updated: '+(r.updated||0)+' | Skipped: '+(r.skipped||0)+'</div>';if(errs.length){html+='<div class="alert alert-warning"><b>Catatan:</b><ul>';errs.forEach(function(x){html+='<li>'+($('<div>').text(x).html())+'</li>';});html+='</ul></div>';}$('#at_import_result').html(html).show();dt.draw(false);}else{$('#at_import_result').html('<div class="alert alert-danger">'+($('<div>').text(r.error_message||'Import gagal.').html())+'</div>').show();}},error:function(x){b.prop('disabled',false).html('<i class="fa fa-upload"></i> Upload & Import');$('#at_import_result').html('<div class="alert alert-danger">'+($('<div>').text(x.responseText||'Import gagal.').html())+'</div>').show();}});});
$('#shift_schedule_id').on('select2:select',function(e){$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=shift_schedule_info',{shift_schedule_id:e.params.data.id,attendance_date:$('#attendance_date').val()},function(r){if(r.status==='good'){atSet('#employee_id',r.employee_id,r.employee_text);atSet('#department_code',r.department_code,r.department_text);atSet('#shift_id',r.shift_id,r.shift_text);atSet('#work_location_id',r.work_location_id,r.work_location_text);$('#planned_start').val(r.planned_start);$('#planned_end').val(r.planned_end);$('#break_minutes').val(r.break_minutes);$('#planned_hours').val(r.planned_hours);}},'json');});
$('#form_attendance').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Attendance');if(r.status==='good'){$('#modal_attendance').modal('hide');dt.draw(false);Swal.fire('Saved',<?=hr_js('hr_attendance_save_success', 'Attendance saved successfully.');?>,'success');}else atError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Attendance');atError(x.responseText);});});
$(document).on('click','.btn-at-detail',function(){$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=detail',{id:$(this).data('id')},function(h){$('#at_detail_body').html(h);$('#modal_at_detail').modal('show');});});
$(document).on('click','.btn-at-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=get',{id:id},function(r){if(r.status!=='good'){atError(r.error_message);return;}atReset('Edit Attendance');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['employee_id','department_code','shift_schedule_id','shift_id','work_location_id'].includes(k))el.val(h[k]);});$('#at_id').val(h.id);atSet('#employee_id',h.employee_id,h.employee_text);atSet('#department_code',h.department_code,h.department_text);atSet('#shift_schedule_id',h.shift_schedule_id,h.shift_schedule_text);atSet('#shift_id',h.shift_id,h.shift_text);atSet('#work_location_id',h.work_location_id,h.work_location_text);$('#attendance_type,#attendance_source,#attendance_status').trigger('change');$('#modal_attendance').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-at-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else atError(r.error_message);},'json');});
$(document).on('click','.btn-at-delete',function(){if($(this).is(':disabled'))return;var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/attendance/attendance_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else atError(r.error_message);},'json').fail(function(x){atError(x.responseText);});});});
});
</script>
